function Input({ label, placeholder, type = "text", value, onChange, optional }) {
  const [focused, setFocused] = useState(false);
  return (
    <div>
      <label style={styles.label}>
        {label} {optional && <span style={{ color: COLORS.textDim, fontWeight: "400", textTransform: "none" }}>(isteğe bağlı)</span>}
      </label>
      <input
        type={type}
        placeholder={placeholder}
        value={value}
        onChange={onChange}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        style={{ ...styles.input, ...(focused ? styles.inputFocus : {}) }}
      />
    </div>
  );
}

// ─── KURYE KAYIT MODALI ───────────────────────────────────────────────────────
function KuryeKayitModal({ onClose, onSuccess }) {
  const [form, setForm] = useState({
    ad: "", soyad: "", tc: "", telefon: "", email: "", sifre: "",
    aracTur: "motorsiklet", aracMarka: "", aracModel: "", plaka: "",
    vergiNo: "", vergiDairesi: "",
  });
  const [errors, setErrors] = useState({});
  const [step, setStep] = useState(1); // 1: kişisel, 2: araç, 3: vergi

  const set = (k) => (e) => setForm((f) => ({ ...f, [k]: e.target.value }));

  const validate1 = () => {
    const e = {};
    if (!form.ad.trim()) e.ad = "Ad zorunludur";
    if (!form.soyad.trim()) e.soyad = "Soyad zorunludur";
    if (!form.telefon.trim()) e.telefon = "Telefon zorunludur";
    if (!form.email.trim()) e.email = "E-posta zorunludur";
    if (!form.sifre.trim() || form.sifre.length < 6) e.sifre = "En az 6 karakter";
    return e;
  };

  const validate2 = () => {
    const e = {};
    if (!form.plaka.trim()) e.plaka = "Plaka zorunludur";
    return e;
  };

  const next = () => {
    if (step === 1) {
      const e = validate1();
      if (Object.keys(e).length) { setErrors(e); return; }
    }
    if (step === 2) {
      const e = validate2();
      if (Object.keys(e).length) { setErrors(e); return; }
    }
    setErrors({});
    setStep(step + 1);
  };

  const submit = () => {
    onSuccess({ ...form, type: "kurye" });
  };

  return (
    <div style={styles.modal} onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div style={{ ...styles.modalBox, position: "relative" }}>
        <button style={styles.closeBtn} onClick={onClose}>×</button>

        {/* Steps */}
        <div style={{ display: "flex", gap: "8px", marginBottom: "24px" }}>
          {["Kişisel Bilgiler", "Araç Bilgileri", "Vergi Bilgileri"].map((s, i) => (
            <div key={i} style={{ flex: 1, textAlign: "center" }}>
              <div style={{
                width: "28px", height: "28px", borderRadius: "50%", margin: "0 auto 4px",
                background: step > i + 1 ? COLORS.success : step === i + 1 ? COLORS.accent : COLORS.inputBg,
                border: `2px solid ${step >= i + 1 ? (step > i + 1 ? COLORS.success : COLORS.accent) : COLORS.cardBorder}`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: "12px", fontWeight: "700", color: step >= i + 1 ? "#fff" : COLORS.textDim,
              }}>
                {step > i + 1 ? "✓" : i + 1}
              </div>
              <div style={{ fontSize: "10px", color: step === i + 1 ? COLORS.accent : COLORS.textDim, fontWeight: "600" }}>{s}</div>
            </div>
          ))}
        </div>

        {step === 1 && (
          <>
            <div style={styles.modalTitle}>🚴 Kurye Ol</div>
            <div style={styles.modalSub}>Kişisel bilgilerini gir, hemen kazanmaya başla</div>
            <div style={styles.row2}>
              <div>
                <Input label="Ad" placeholder="Ahmet" value={form.ad} onChange={set("ad")} />
                {errors.ad && <div style={styles.errorText}>{errors.ad}</div>}
              </div>
              <div>
                <Input label="Soyad" placeholder="Yılmaz" value={form.soyad} onChange={set("soyad")} />
                {errors.soyad && <div style={styles.errorText}>{errors.soyad}</div>}
              </div>
            </div>
            <div>
              <Input label="TC Kimlik No" placeholder="12345678901" value={form.tc} onChange={set("tc")} optional />
            </div>
            <div>
              <Input label="Telefon" placeholder="0532 123 4567" value={form.telefon} onChange={set("telefon")} />
              {errors.telefon && <div style={styles.errorText}>{errors.telefon}</div>}
            </div>
            <div>
              <Input label="E-posta" placeholder="ahmet@email.com" type="email" value={form.email} onChange={set("email")} />
              {errors.email && <div style={styles.errorText}>{errors.email}</div>}
            </div>
            <div>
              <Input label="Şifre" placeholder="En az 6 karakter" type="password" value={form.sifre} onChange={set("sifre")} />
              {errors.sifre && <div style={styles.errorText}>{errors.sifre}</div>}
            </div>
          </>
        )}

        {step === 2 && (
          <>
            <div style={styles.modalTitle}>🚗 Araç Bilgileri</div>
            <div style={styles.modalSub}>Araç türüne göre uygun teslimatlar sana gelecek</div>
            <label style={styles.label}>Araç Türü</label>
            <div style={{ display: "flex", gap: "10px", marginBottom: "4px" }}>
              {[
                { val: "motorsiklet", label: "🏍️ Motorsiklet", sub: "≤15 kg" },
                { val: "otomobil", label: "🚗 Otomobil", sub: "15–100 kg" },
                { val: "kamyonet", label: "🚐 Kamyonet", sub: "15–100 kg" },
              ].map((a) => (
                <div key={a.val}
                  onClick={() => setForm((f) => ({ ...f, aracTur: a.val }))}
                  style={{
                    flex: 1, padding: "12px 8px", borderRadius: "10px", textAlign: "center", cursor: "pointer",
                    border: `2px solid ${form.aracTur === a.val ? COLORS.accent : COLORS.cardBorder}`,
                    background: form.aracTur === a.val ? COLORS.accentGlow : COLORS.inputBg,
                    fontSize: "12px", fontWeight: "700",
                    color: form.aracTur === a.val ? COLORS.accent : COLORS.textMuted,
                    transition: "all 0.2s",
                  }}>
                  <div style={{ fontSize: "20px", marginBottom: "4px" }}>{a.label.split(" ")[0]}</div>
                  <div>{a.label.split(" ")[1]}</div>
                  <div style={{ fontSize: "10px", color: COLORS.textDim, marginTop: "2px" }}>{a.sub}</div>
                </div>
              ))}
            </div>
            <div style={styles.row2}>
              <Input label="Araç Markası" placeholder="Honda" value={form.aracMarka} onChange={set("aracMarka")} optional />
              <Input label="Araç Modeli" placeholder="PCX 125" value={form.aracModel} onChange={set("aracModel")} optional />
            </div>
            <div>
              <Input label="Plaka" placeholder="34 ABC 123" value={form.plaka} onChange={set("plaka")} />
              {errors.plaka && <div style={styles.errorText}>{errors.plaka}</div>}
            </div>
          </>
        )}

        {step === 3 && (
          <>
            <div style={styles.modalTitle}>📋 Vergi Bilgileri</div>
            <div style={styles.modalSub}>İsteğe bağlı — daha sonra da ekleyebilirsin</div>
            <div style={styles.infoBox}>
              💡 Vergi bilgilerin olmasa da kayıt olabilirsin. Ödeme alabilmek için daha sonra eklemeniz gerekecek.
            </div>
            <Input label="Vergi No" placeholder="1234567890" value={form.vergiNo} onChange={set("vergiNo")} optional />
            <Input label="Vergi Dairesi" placeholder="Kadıköy Vergi Dairesi" value={form.vergiDairesi} onChange={set("vergiDairesi")} optional />
          </>
        )}

        <div style={{ display: "flex", gap: "10px", marginTop: "24px" }}>
          {step > 1 && (
            <button onClick={() => setStep(step - 1)} style={styles.btnSecondary}>
              ← Geri
            </button>
          )}
          {step < 3 ? (
            <button onClick={next} style={{ ...styles.btnPrimary, flex: 1 }}>
              Devam →
            </button>
          ) : (
            <button onClick={submit} style={{ ...styles.btnPrimary, flex: 1 }}>
              ✓ Kayıt Ol
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

